var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"분명, 오늘 파티는 이 도시에서 가장 화끈한 파티 피플만 모이기로 했을 텐데…….","JPN":"確か、今日のパーティーはこの街で一番ホットなパーティー好きだけを呼んでいたはずだけど……","ENG":"Tonight's party was only for the hottest partygoers in the city...","TWN":"今天的派對我明明只有邀請現在城市裡最紅的人……"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"너흰 다 뭐야? 어딜 초대장도 없이, 내 집에 흙발로 기어 들어와?","JPN":"あなたたちは誰？　招待状もなしに私の家に土足で上がってくるなんて。","ENG":"But what are you all doing here? How dare you drag your muddied shoes into my home! And without even an invitation at that!","TWN":"你們是什麼東西？連邀請函都沒有，竟敢用你們的髒腳踏入我家？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"형제, 이 여자가 확실한가?","JPN":"兄弟、この女で間違いないか？","ENG":"Brother, are you sure it is her?","TWN":"兄弟，確定是這個女人嗎？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L7_1","type":"dialog","speaker":"SHIELD_ADMIN_NULL_NULL","text":{"KOREA":"맞아, 그 녀석들의 다음 상대. 건틀렛 리그 챔피언이다.","JPN":"ああ、あいつらの次戦相手。ガントレットリーグのチャンピオンだ。","ENG":"Yes. She is the Gauntlet champion. Their next opponent.","TWN":"沒錯，她是聖鎧聯賽的冠軍，是他們的下一場比賽的對手。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"흐응, 형제라?","JPN":"ふうん、兄弟ねえ？","ENG":"Hmm? \\"Brother?\\"","TWN":"喔呵，兄弟嗎？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그래, 어용 테러리스트들이 나한테 무슨 볼일이지?","JPN":"御用テロリストが私に何の用？","ENG":"So? What business do the government terrorists have with me?","TWN":"好吧，皇家恐怖分子找我有什麼事？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"뭔지는 몰라도, 내가 납득할 수 있는 이유여야만 할 거야.","JPN":"何なのかは知らないけど、私を納得させられる理由はあるんでしょうね？","ENG":"Whatever it is, it'd better be a good enough reason.","TWN":"我是不清楚是什麼事，但最好是我能接受的理由。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"……그렇군. 아직 전달받지 못한 건가?","JPN":"……そうか。まだ伝えらえれていないんだな。","ENG":"...I see. So she has not received word yet?","TWN":"……是嗎，你還沒有收到消息嗎？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"뭐라고?","JPN":"何ですって？","ENG":"What's that now?","TWN":"什麼？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"그만. 그들과 거래를 맺은 것은 우리 측이다. 오지만디아스.","JPN":"やめろ。彼らと契約を結んだのは我々だ。オジマンディアス。","ENG":"Enough. They are under a contract with us, Ozymandias.","TWN":"好了，奧茲曼迪亞斯，我們和他們有交易。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L20_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"이번 결승에 그자들을 엔트리에 포함시키도록.","JPN":"今回の決勝に彼らをエントリーさせろ。","ENG":"Include them in your roster for the finals.","TWN":"把他們加到這次決賽的選手名單裡吧。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"내가 왜?","JPN":"なぜ私が？","ENG":"Why should I?","TWN":"憑什麼？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"아무리 내 스폰서라고 할지라도, 경기 방식에 참견하는 건 선을 넘는 짓이야.","JPN":"いくらスポンサーでも、試合の進め方にまで口出しするのは一線を越える行為よ。","ENG":"You may be my sponsor, but you're crossing a line by meddling with my match.","TWN":"就算你是我的贊助商，但干涉比賽是越界行為。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"당신들 눈에는 내가 그렇게 만만하게 보이나 봐?","JPN":"私も随分となめられたものね。","ENG":"Do I look like some chump to you?","TWN":"你們覺得我很好欺負是嗎？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"먼저 선을 넘은 건 그쪽일 텐데?","JPN":"先に一線を越えてきたのは、そちらの方だろう。","ENG":"I believe you are the one who crossed the line first.","TWN":"先越界的人是你吧？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L28_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"일방적으로 와일러의 백업 멤버를 스캐빈저로 변경한 게 누구지?","JPN":"一方的にワイラーのバックアップメンバーをスカベンジャーに変更したのはどこの誰だ？","ENG":"Who was the one to change Wyler's backup to Scavengers?","TWN":"擅自把瓦勒的替補選手換成清道夫的是誰？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"덕분에 조니 앤 멜로니까지 써 가면서 꺼낸 광고탑을 폐기 처분해야 했어.","JPN":"おかげでジョニー＆メロニーまで使って得た広告塔を廃棄処分に追いやらざるをえなかった。","ENG":"Thanks to you, I had to discard the advertisement tower I got through hiring Jonie & Melonie.","TWN":"我砸重金請來強尼＆梅蘭妮，好不容易才弄出來的活招牌，拜你所賜現在整個血本無歸。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L30_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"우리 측의 손실이 얼마나 되는 줄 아나?","JPN":"こちら側の損失がどれほどかわかっているのか？","ENG":"Do you know how much money we lost because of that?","TWN":"你知道我們損失多少錢嗎？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"나는 그 녀석 수준에 맞게 실력 있는 놈들을 붙여줬을 뿐이야.","JPN":"私はあいつのレベルに見合った実力者をつけてやっただけよ。","ENG":"All I did was replace the members with ones that matched his skill level.","TWN":"我只是替那傢伙安排幾個符合他水準的人而已。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"경기 결과는 순전히 와일러가 우리 기대에 못 미쳐서 나온 거고.","JPN":"試合の結果はあくまでワイラーが私たちの期待以下だったから、そうなっただけ。","ENG":"The result of the match was purely because Wyler did not perform up to our expectations.","TWN":"比賽結果之所以會那樣，完全是因為瓦勒無法達到我們的期待。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"그래. 우리도 네 수준을 생각해서 그자들을 부른 거다.","JPN":"そうだな。それこそ我々も君のレベルを考慮して、彼らを呼んだんだ。","ENG":"Yes. And we have also brought you new team members that match your skill level.","TWN":"很好，那我們也只是安排幾個符合你水準的人而已。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"실력만큼은 펠릭스의 부하들이 네 부하들보다 몇 수 위니까 말이야.","JPN":"実力だけなら、フェリックスの部下たちの方が君のそれよりも数段上だからな。","ENG":"Felix's men will be far better skilled than the ones you have now.","TWN":"論實力，菲利克斯的手下比你的手下強多了。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"하! 지금 내 승리를 못 믿겠다는 거야?","JPN":"はっ！　私の勝利を不安視でもしているってこと？","ENG":"Ha! You don't think I can win, do you?","TWN":"哈！你這是信不過我的能力？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"손익에 따라 움직이는 해적들은 차라리 다루기라도 쉽지.","JPN":"損得勘定だけで動く海賊の方が、むしろ操縦の面では苦労しない。","ENG":"At least pirates are easier to deal with as they only follow the money.","TWN":"那些見錢眼開的海盜還好控制，"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L37_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"사상에 취한 저 정신병자들이 내 명령을 따르기나 하겠어?","JPN":"あんな思想に酔いしれた異常者たちが私の命令に従うと思う？","ENG":"How am I supposed to order around lunatics who are drunk on their ideology?","TWN":"但那些腦袋不正常的精神病怎麼可能聽我的命令？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"플라티나 측은 이번 결승을 도우면 곱슬머리의 신병을 넘겨주겠다더군.","JPN":"プラチナは今回の決勝での勝利を手伝えば、縮れ毛の身柄を引き渡すとの条件を提示した。","ENG":"Platina has promised to hand over Curly hair if we help you win the finals.","TWN":"白金表示，要是你願意幫忙，就把自然捲交給你。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L40_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"계약에 따라, 경기 중에는 네 지시를 따르겠다. 챔피언.","JPN":"契約に基づき、試合中はお前の指示に従おう。チャンピオン。","ENG":"According to our contract, we will follow your orders during the match, champion.","TWN":"而且按照合約，在比賽中我們會聽從你的指示，冠軍。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"고집은 그만 부려라, 오지만디아스.","JPN":"意地を張るのはもうやめろ、オジマンディアス。","ENG":"Stop being so stubborn, Ozymandias.","TWN":"別再堅持了，奧茲曼迪亞斯。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"말했을 텐데, 우리에게 필요한 건 엔터테인먼트가 아니라, 이미지라고.","JPN":"言ったはずだ。我々に必要なのはエンターテインメントではなく、イメージだと。","ENG":"I have told you before that what we need is not entertainment but a certain image.","TWN":"我說過，我們需要的不是娛樂效果，而是形象。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"쳇, 어이가 없네.","JPN":"ちっ、勝手なことを。","ENG":"Tch, you can't be serious.","TWN":"嘖，真是無言。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"좋아. 대신 경기 중에 이 녀석들의 운용은 내 마음대로 하겠어. 불만 없지?","JPN":"いいわ。その代わり試合中の指揮権は私が持つからね、いい？","ENG":"Fine. But you can't complain about how I decide to use them in the match. Got it?","TWN":"好吧，但在比賽中由我來支配這些傢伙，你沒意見吧？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"다음 계약 때 보자고. 이번 일, 순순히 넘어갈 생각 없으니까 말이야.","JPN":"次の契約まで覚えておきなさいよ。今回の件、ただでは済まさないわ。","ENG":"I'll see you again when we renew our contract. I won't let this go easily.","TWN":"等下一次簽約時候再說吧，這次的事我不會就這麼算了。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"}]`);export{e as default};